<template>
  <div>
    <link rel="stylesheet" href="/assets/20242030/css/materialdesignicons.min.css">
    <link rel="stylesheet" href="/assets/20242030/css/bootstrap.min.css">
    <!-- <link rel="stylesheet" href="/assets/20242030/css/style_maps.css"> -->

    <v-main>
      <div id="viewDiv" ref="mapView"></div>
    </v-main>

    <v-footer app color="#9b162e" class="text-white grays">
      <template>
        Gobierno de Puebla
        <v-spacer></v-spacer>
        <v-btn class="mx-2" fab dark color="green" title="Obtener Ubicación" small>
            <v-icon @click="getLocate()" :disabled="btnGet" dark>mdi-map-marker </v-icon>
        </v-btn>
        <v-btn class="mx-2" fab dark color="primary" title="Confirmar Ubicación" small>
            <v-icon  @click="sendLocate()" :disabled="btnSend" dark>mdi-send </v-icon>
        </v-btn>
      </template>
    </v-footer>
    <loader-comp />
  </div>
</template>

<script>
import '@arcgis/core/assets/esri/themes/light/main.css'
import Map from '@arcgis/core/Map'
import MapView from '@arcgis/core/views/MapView'
import * as reactiveUtils from '@arcgis/core/core/reactiveUtils'
import Graphic from '@arcgis/core/Graphic'
import GraphicsLayer from '@arcgis/core/layers/GraphicsLayer'
import Point from '@arcgis/core/geometry/Point'

// import axios from 'axios'
import { mapState, mapActions } from 'vuex'

import LoaderComp from '@/components/20242030/LoaderComp.vue'

export default {
  name: 'ArcGISMap',
  components: { // Importación de componentes hijos
    LoaderComp
  },
  directives: {}, // Directivas personalizadas
  filters: {}, // Filtros (si usas)

  // 2️⃣ Propiedades de entrada
  props: {},
  mixins: {},
  extends: {},

  // 3️⃣ Datos reactivas
  data () {
    return {
      // map
      vector: [
        'streets-navigation-vector',
        'streets',
        'topo-vector',
        'satellite',
        'hybrid',
        'dark-gray-vector',
        'oceans',
        'national-geographic',
        'terrain',
        'satellite'
      ],
      view: undefined,
      map: undefined,
      stopWatchHandle: null,
      graphicsLayer: null,
      // vue
      check_type: '',
      forms: { lng: 0, lat: 0 },
      btnSend: true,
      btnGet: true
    }
  },
  computed: {
    ...mapState('S20242030', [
      'dialog_loader'
    ])
  },

  // 4️⃣ Observadores
  watch: {},

  // 5️⃣ Métodos
  methods: {
    // vuex
    ...mapActions('S20242030', [
      'setSleep'
    ]),
    // map
    async drawGraphic (element) {
      // console.log('drawGraphic() -->', element)
      // Si no existe la capa, créala con zIndex alto
      if (!this.graphicsLayer) {
        this.graphicsLayer = new GraphicsLayer({
          id: 'graphics-layer',
          title: 'Marcadores',
          zIndex: 100
        })
        this.map.add(this.graphicsLayer)
      }

      this.graphicsLayer.removeAll()
      await this.setSleep(100)

      const point = new Point({
        latitude: element.lat,
        longitude: element.lng
      })

      const markerSymbol = {
        type: 'simple-marker',
        width: '10px',
        height: '10px',
        color: [44, 214, 225]
      }

      const pointGraphic = new Graphic({
        geometry: point,
        symbol: markerSymbol
      })

      this.graphicsLayer.add(pointGraphic)

      this.view.center = [element.lng, element.lat]
      this.view.zoom = 17
    },
    async initMap () {
      this.map = new Map({
        basemap: this.vector[0] // 'streets-navigation-vector'
      })

      this.view = new MapView({
        container: this.$refs.mapView,
        map: this.map,
        center: [-98.18635039767328, 19.054906905810686], // Estadio Olímpico Zaragoza
        zoom: 17
      })

      await this.view.when() // Esperar a que la vista esté lista antes de agregar el componente

      this.stopWatchHandle = reactiveUtils.watch(
        () => this.view.updating, // 🔹 propiedad reactiva
        async (updating) => {
          if (!updating) {
            await this.setSleep(1500) // 🔸 esperamos un poco para asegurar que todo terminó de renderizar
            this.dialog_loader.actived = false
            this.btnGet = false
          }
        }
      )
    },
    // vue
    async checkDevice () {
      // console.log('checkDevice()')
      const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent) ||
      window.matchMedia('(max-width: 768px)').matches
      if (!isMobile) {
        alert('¡Para poder ingresar tienes que registrarte en tu celular gracias!')
        window.location.href = 'http://serviciosippi.serveirc.com/IPPI'
      }
    },
    async getLocate () {
      if (navigator.geolocation) {
        this.dialog_loader.actived = true

        // ---- Busca la posicion solo una vez ----
        await navigator.geolocation.getCurrentPosition(position => {
          this.forms.lat = position.coords.latitude
          this.forms.lng = position.coords.longitude

          const location = this.forms.lat + ', ' + this.forms.lng
          this.dialog_loader.message = `Por favor espere... <br> Ubicación: ${location}`

          this.btnSend = false
          this.drawGraphic({ lng: this.forms.lng, lat: this.forms.lat })
        }, error => {
          console.error(error)
          alert('¡El dispositivo o la red no permite obtener su ubicación, favor de activar el GPS y conéctese a una red más estable, ejemplo: WIFI!')
          this.view.center = [-98.18635039767328, 19.054906905810686]
          this.view.zoom = 17

          this.dialog_loader.actived = false
          this.forms.lat = ''
          this.forms.lng = ''
          this.btnSend = true
        })

        // ---- Sigue la ubicacion del usuario, ejecutandose cada cierto tiempo ----
        // await navigator.geolocation.watchPosition(position => {
        //   this.DrawGraphic({ lng: position.coords.longitude, lat: position.coords.latitude })
        // }, error => {
        //   console.error('Geolocation error:', error)
        //   alert('¡Su conexión no es segura, intente conectarse en otra red para obtener su ubicación!')
        // }, { timeout: 5000 })
      } else {
        alert('¡Error! Este navegador no soporta la Geolocalización.')
      }
    },
    async sendLocate () {
      const location = `${this.forms.lng},${this.forms.lat}` // -98.18635039767328, 19.054906905810686
      if (!/^-?\d{1,3}\.\d+,-?\d{1,3}\.\d+$/.test(location)) {
        return alert('¡Los datos no son válidos!, favor de actualizar la ubicación!')
      }

      // console.log('sendLocate() -->', location)
      window.location.href = `http://serviciosippi.serveirc.com/IPPI/checador.html?t=1&lng=${this.forms.lng}&lat=${this.forms.lat}`
    }
  },

  // 6️⃣ Ciclo de vida
  beforeCreate () {},
  async created () {
    document.title = 'mi ubicación'
    await this.checkDevice()
    this.dialog_loader.actived = true
    this.dialog_loader.message = 'Por favor espere...'
  },
  beforeMount () {},
  mounted () {
    this.initMap()
    window.addEventListener('resize', this.checkDevice)
  },
  beforeUpdate () {},
  updated () {},
  beforeDestroy () {
    if (this.stopWatchHandle) {
      this.stopWatchHandle.remove()
      this.stopWatchHandle = null
    }

    if (this.view) {
      this.view.destroy()
      this.view = null
    }
  },
  destroyed () { }

  // 7️⃣ Hooks específicos (como de rutas, etc.)
  // beforeRouteEnter() {}, etc.

}
</script>

<style scoped>
  #viewDiv {
    width: 100%;
    height: 94.5vh;
    margin: 0;
    padding: 0;
  }
</style>
